INSERT INTO fonts (name, description, creator_id, style_id, source, distribution_method_id, created_at, updated_at) VALUES
('Alegreya', 'Alegreya была выбрана в качестве одного из 53 «Шрифтов десятилетия» на конкурсе ATypI Letter2 в сентябре 2011 года и вошла в топ‑14 текстовых шрифтовых систем. Также шрифт был отмечен на Второй ибероамериканской биеннале дизайна (2nd Biennial Iberoamericana de Diseño), проходившей в Мадриде в 2010 году.\n\nAlegreya — это шрифт, изначально созданный для литературы. Среди его главных особенностей — динамичный и разнообразный ритм, который облегчает чтение длинных текстов. Кроме того, он придаёт свежесть странице, отсылает к каллиграфической букве — но не в буквальном прочтении, а через современный типографический язык.\n\nКурсивное начертание проработано с таким же вниманием к деталям, как и прямое. Жирные начертания (Bold) получились выразительными, а сверхжирные (Black) — по‑настоящему экспериментальными для данного жанра. Также существует родственное семейство с капителью (Small Caps).\n\nШрифт Alegreya не только демонстрирует отличные функциональные качества, но и позволяет добиться цельного и гармоничного вида текста благодаря элементам, разработанным в атмосфере разнообразия.\n\nШрифтовая система Alegreya — это «суперсемейство», изначально созданное для литературы. Оно включает родственные семейства с засечками (serif) и без засечек (sans serif).', 6, 2, 'https://fonts.google.com/specimen/Alegreya', 1, NOW(), NOW()),
('Alice', 'Ксения Ерулевич, дизайнер шрифта Alice, вдохновилась романом Льюиса Кэрролла и решила создать шрифт, который подойдёт для вёрстки этой книги.\n\nПолучилось эклектично и причудливо, в старомодном стиле: с расширенными пропорциями, открытыми апертурами и мягкими округлыми формами. Шрифт идеально подходит как для набора длинных медитативных текстов, так и для заголовков.\n\nЭто первый шрифт Ксении — он был создан в рамках её дипломного проекта по курсу «Шрифт и типографика» в Москве, Россия.\n\nШрифт выпущен студией Cyreal при участии Гаяне Багдасарян и Алексея Ваняшина.', 7, 2, 'https://fonts.google.com/specimen/Alice', 1, NOW(), NOW()),
('AlumniSans', 'Изначально шрифт Alumni был вдохновлён жирным начертанием шрифта Impact, но вскоре эволюционировал: в семействе появилось множество начертаний — от «чёрного» (Black), унаследованного от прародителя, до сверхтонкого (Thin).\n\nКрайние начертания (Thin и Black) предназначены для акцидентного использования (заголовков, плакатов, вывесок), тогда как остальные веса можно применять для более традиционных задач текстового дизайна.\n\nШрифт Alumni доступен в прямом (roman) и курсивном (italic) начертаниях. Он поддерживает латинские наборы символов, включая языки Западной и Центральной Европы, а также вьетнамский язык.', 8, 9, 'https://fonts.google.com/specimen/Alumni+Sans', 1, NOW(), NOW()),
('Amatic SC', 'Amatic SC (Small Caps) — это простой, но эффективный веб‑шрифт, нарисованный от руки. Его можно использовать для заголовков и небольших фрагментов текста.\n\nИзначально шрифт был разработан Верноном Адамсом (Vernon Adams) и задумывался как свободно доступный в интернете — для использования веб‑браузерами на настольных компьютерах, ноутбуках и мобильных устройствах.\n\nШрифт поддерживает как латинский, так и еврейский алфавиты, а также 70 других алфавитов. Латинская версия была изначально разработана Верноном Адамсом. Еврейская версия создана Беном Натаном (Ben Nathan), который также доработал дизайн латинского алфавита. Томас Джокин (Thomas Jockin) выполнил корректировку межбуквенных расстояний (трекинг) и кернинг всего шрифта.', 1, 11, 'https://fonts.google.com/specimen/Amatic+SC', 1, NOW(), NOW()),
('Anonymous Pro', 'Anonymous Pro — это семейство из четырёх моноширинных шрифтов, разработанных специально для программирования. Оно вдохновлено шрифтом Anonymous 9 — бесплатным растровым шрифтом для Macintosh, созданным в середине 90‑х годов Сьюзан Леш (Susan Lesch) и Дэвидом Лэмкином (David Lamkins). Anonymous 9 задумывался как более читаемая альтернатива Monaco — моноширинному системному шрифту Macintosh.\n\nСимволы, которые можно спутать друг с другом (O, 0, I, l, 1 и т. д.), имеют отчётливо различающиеся формы — это упрощает их идентификацию в контексте исходного кода. Прямое и жирное начертания содержат встроенные растровые версии для самых маленьких размеров (10–13 ppem).', 9, 13, 'https://fonts.google.com/specimen/Anonymous+Pro', 1, NOW(), NOW()),
('Arimo', 'Arimo был разработан Стивом Маттесоном (Steve Matteson) как инновационный, свежий дизайн шрифта без засечек, метрически совместимый с Arial™.\n\nШрифт Arimo обладает улучшенными характеристиками читаемости на экране, включает пан‑европейский набор символов WGL и решает задачи разработчиков, которые ищут шрифты с совместимой шириной символов — чтобы обеспечить переносимость документов между разными платформами.\n\nВ мае 2013 года шрифт был обновлён: улучшена хинтовка (подсказки для отображения на экранах с низким разрешением). После этого он был выпущен под лицензией Apache 2.0.', 2, 8, 'https://fonts.google.com/specimen/Arimo', 1, NOW(), NOW()),
('Arsenal', 'Arsenal — полугротеск с традиционными формами. Шрифт в первую очередь разработан для основного текста и предназначен для профессиональной визуальной коммуникации.\n\nОсобые качества форм букв — такая как тонкая модуляция контраста, выразительная грация и экспрессивность. Несколько лирическое настроение шрифта Arsenal отражает его украинское происхождение.\n\nГлавные особенности дизайна:\n - узкие пропорции, позволяющие экономно размещать текст;\n - умеренная апертура;\n - заметный контраст.\n\nЭти черты формируют важные свойства шрифта: нейтральность, чёткость и динамичность.\n\nВ 2011 году этот шрифт, созданный Андрием (Andrij), стал победителем Украинского конкурса шрифтового дизайна «Mystetsky Arsenal». Жюри отбирало работы по трём основным критериям:\n - соответствие духу времени (zeitgeist);\n - практичность;\n - ощущение украинскости.\n\nПобедившая работа Андрия получила название Arsenal и была опубликована под лицензией SIL Open Font License.', 10, 7, 'https://fonts.google.com/specimen/Arsenal', 1, NOW(), NOW()),
('Bad Script', 'Bad Script начался с простого шестибуквенного логотипа и развился в отдельный шрифт, поддерживающий наборы символов латиницы и кириллицы. Он полностью создан с помощью графического планшета — чтобы имитировать небрежный, но аккуратный рукописный почерк. Шрифт разработан так, чтобы напоминать собственный почерк дизайнера, но при этом быть систематизированным и плавным.\n\nОбновление 2024 года улучшило кернинг и расширило языковую поддержку. Также были исправлены некоторые ошибки и усовершенствован дизайн.', 11, 11, 'https://fonts.google.com/specimen/Bad+Script', 1, NOW(), NOW()),
('Balsamiq Sans', 'Balsamiq Sans — рукописный шрифт, созданный специально для Balsamiq Wireframes; используется начиная с версии 2.1.\n\nШрифт содержит 942 глифа в двух начертаниях (с курсивом/наклоном) и включает:\n - базовый и расширенный набор латинских символов;\n - кириллицу;\n - базовые символы и «дингбаты» (декоративные символы);\n - математические и технические символы;\n - знаки препинания.', 12, 10, 'https://fonts.google.com/specimen/Balsamiq+Sans', 1, NOW(), NOW()),
('Bellota', 'Bellota — декоративный шрифт без засечек с низким контрастом, предлагающий текстовые и росчерковые (swash) альтернативные варианты символов. Он достаточно милый!\nШрифт представлен в двух вариантах: Normal («Обычный») и Text («Текстовый»).', 13, 9, 'https://fonts.google.com/specimen/Bellota', 1, NOW(), NOW()),
('Bitter', 'С каждым днём люди всё больше читают и взаимодействуют с текстом на экранах. То, что отображается на экране, становится важнее того, что выходит из принтера. С ростом популярности электронных книг дизайнеры шрифтов усердно работают над поиском идеальных решений для чтения с экрана.\n\nВдохновлённая любовью к пикселю, Сол Матас (Sol Matas) создала шрифт Bitter. Это «современный» шрифт с засечками (slab serif) для набора текста, специально разработанный для комфортного чтения на любом компьютере или устройстве.\n\nМощный дизайн берёт начало в строгости пиксельной сетки и основан на рациональных, а не эмоциональных принципах. Шрифт сочетает большую высоту строчных букв (x‑height) и читаемость гуманистической традиции с тонкими особенностями в начертании символов — они задают определённый ритм плавному тексту.\n\nУ шрифта Bitter небольшая вариация толщины штрихов, а стиль Regular толще, чем обычный «Regular» для полиграфического дизайна. Это создаёт насыщенный цвет абзацев, который подчёркивают засечки: они такой же толщины, как штрихи, и имеют квадратные окончания.\n\nКаждый глиф тщательно проработан: на первом этапе проектирования, полностью выполненном в пиксельной сетке, особое внимание уделено качеству кривых. Гарнитура сбалансирована и вручную откернингована — для неё требуется очень мало кернинговых пар.', 3, 5, 'https://fonts.google.com/specimen/Bitter', 1, NOW(), NOW()),
('Brygada 1918', 'Brygada 1918 — проект возрождения шрифта, созданный к празднованию 100‑летия независимости Республики Польша в 2018 году при поддержке программы «Независимость» и президента Республики Польша.\nШрифт основан на записи из каталога Национальной шрифтолитейной мастерской 1954 года и наборе матриц, обнаруженных в Музее книжного искусства Яном Жужно (Janusz Tryzno) в 2016 году. Более подробную информацию можно найти на сайте проекта и в Google Design.\n\nВозрождение забытого шрифта: «шрифтовые детективы» дают жизнь Brygada\nЗагадочные польские шрифтовые матрицы пробуждают интерес к утерянному шрифту, созданному до Второй мировой войны.\nМужчина находит неиспользованный шрифт в пыльных грудах металлических пластин и блоков. Его заинтриговали загадочные буквы «K» и «R» с завитушками и рукописная записка на старой коричневой бумаге с надписью «Brygada». Он начинает своего рода археологическую экспедицию, чтобы исследовать происхождение шрифта, — и вдохновляет команду на его возрождение с помощью программного обеспечения XXI века и микроскопической камеры.\nЭто сюжет нового фильма про Индиану Джонса или история создания обновлённого оцифрованного шрифта?\nВторое. Это история шрифта Brygada — утерянного и забытого шрифта XX века, воссозданного для XXI века.\nДело было летом 2015 года. Г‑н Ян Жужно (Janusz Tryzno), владелец Музея книжного искусства в Лодзи (Łódź, произносится «Вудже»), расположенном в вилле XIX века, перебирал груды шрифтовых матриц (металлических блоков с формами букв, используемых для отливки литер) и металлических пластин, завёрнутых в коричневую бумагу, из Польской национальной шрифтолитейной мастерской.\nОбнаружив матрицы шрифта Brygada, он попросил волонтёров музея, Пшемыслава Хоффера (Przemysław Hoffer) и Бориса Космынку (Borys Kosmynka), изучить матрицы — чтобы понять, можно ли вернуть шрифт к жизни.', 14, 3, 'https://fonts.google.com/specimen/Brygada+1918', 1, NOW(), NOW()),
('Cascadia Mono', 'Cascadia Code — это увлекательный шрифт с открытым исходным кодом, который появился в рамках проекта Windows Terminal как замена шрифту Consolas.\n\nЕго создали, чтобы придать индивидуальность моноширинным средам (особенно это заметно в курсиве!), при этом сохранив высокую степень читаемости и производительности — даже на экранах с низким разрешением и при небольших размерах текста.\n\nШрифт также поддерживает широкий набор языков, включая расширенную латиницу (в т. ч. вьетнамский), греческий, кириллицу, арабский и иврит.\n\nУ Cascadia Code есть альтернативная версия — Cascadia Mono. В ней отключены лигатуры для программирования — это подойдёт тем, кто предпочитает видеть один глиф на одну позицию (один символ в одной ячейке).', 4, 13, 'https://fonts.google.com/specimen/Cascadia+Mono', 1, NOW(), NOW()),
('Caveat', 'Caveat — это семейство рукописных шрифтов, разработанное Пабло Импаллари (Pablo Impallari). Шрифт подходит как для коротких пометок, так и для набора основного текста. Для другого стиля существует родственное семейство — Caveat Brush.\n\nШрифты поддерживают функции OpenType, которые позволяют буквам слегка меняться в зависимости от их положения в слове — благодаря этому создаётся эффект естественного рукописного текста.\n\nПроект Caveat был заказан компанией Google у студии Impallari Type — дизайн‑студии шрифтов из Росарио (Аргентина).', 5, 11, 'https://fonts.google.com/specimen/Caveat', 1, NOW(), NOW()),
('Comfortaa', 'Comfortaa — округлый геометрический шрифт без засечек, созданный для использования в крупном кегле. Он абсолютно бесплатен — как для личного, так и для коммерческого применения.\n\nЕсли вам понравился шрифт, посетите мою страницу на [DeviantArt](https://www.deviantart.com/aajohan/art/Comfortaa-font-105395949) и добавьте его в избранное (но, разумеется, только если он вам действительно нравится). Также буду рад любым комментариям — я открыт к критике. Мне было бы очень интересно увидеть, как используется мой шрифт: смело оставляйте комментарии со ссылкой на вашу работу или отправьте мне сообщение.\n\nНадеюсь, вам понравится работать с моим шрифтом!', 15, 10, 'https://fonts.google.com/specimen/Comfortaa', 1, NOW(), NOW()),
('Comic Relief', 'Comic Relief — это шрифт, спроектированный так, чтобы быть метрически эквивалентным популярному Comic Sans MS. Comic Relief можно использовать вместо Comic Sans MS без необходимости перемещать, изменять размер или перенастраивать какую‑либо часть текста. Идеально подходит для объявлений о пропавших котах и всех ваших задач с WordArt!', 16, 10, 'https://fonts.google.com/specimen/Comic+Relief', 1, NOW(), NOW()),
('Cormorant Garamond', 'Cormorant — бесплатное семейство акцидентных шрифтов, разработанное Кристианом Тальманном (Christian Thalmann). В настоящее время проект включает в общей сложности 45 файлов шрифтов, охватывающих:\n - 9 различных визуальных стилей: Roman, Italic, Infant, Infant Italic, Garamond, Garamond Italic, Upright Cursive, Small Caps и Unicase;\n - 5 начертаний по насыщенности: Light, Regular, Medium, SemiBold и Bold.\n\nШрифт Cormorant был задуман, отрисованы, отмерен (выставлены межбуквенные расстояния), откернингован, запрограммирован, интерполирован и полностью произведён Кристианом Тальманном из Catharsis Fonts. С иллюстрированной презентацией и описанием семейства можно ознакомиться на странице проекта на Behance.\n\nХотя этот проект во многом вдохновлён бессмертным наследием Клода Гарамона (Claude Garamont), Кристиан не использовал какой‑либо конкретный шрифт в качестве отправной точки или прямого образца для дизайна. Большинство глифов были нарисованы с нуля. Если ему требовалось руководство по какому‑то конкретному символу, он искал по запросу «Garamond» и просматривал результаты, чтобы получить общее впечатление.\n\nАвтор выражает благодарность творческим людям с форумов Typophile, TypeDrawers и Typografie, а также GitHub — за обширные знания о шрифтовом дизайне и за множество отличных отзывов о Cormorant в процессе разработки. Он также благодарит неутомимых специалистов из Glyphs, в частности Райнера Эриха Шайхельбауэра (Rainer Erich Scheichelbauer) из Schriftlabor и Георга Зайферта (Georg Seifert). Особая благодарность — Дэйву Кроссленду (Dave Crossland) и Google Fonts за то, что они сделали возможным свободное распространение этого семейства шрифтов благодаря щедрой финансовой поддержке процесса разработки.', 17, 2, 'https://fonts.google.com/specimen/Cormorant+Garamond', 1, NOW(), NOW()),
('EB Garamond', 'EB Garamond призван стать превосходным классическим шрифтом в стиле Гарамонда. Это общественный проект по возрождению знаменитых гуманистических шрифтов Клода Гарамона (Claude Garamont), созданных в середине XVI века.\n\nЦифровая версия максимально точно воспроизводит оригинальный дизайн Клода Гарамона. Источником для форм букв послужил скан образца, известного как «образец Бернера» («Berner specimen»), составленный в 1592 году Конрадом Бернером (Conrad Berner) — зятем и преемником Кристиана Эгенольфа (Christian Egenolff) в его типографии. Этот образец демонстрирует римское начертание Гарамона и курсивное начертание Гранжона (Granjon) в разных размерах. Отсюда и название проекта: Egenolff‑Berner Garamond.\n\nПочему ещё один Гарамонд? Этот шрифт — ключевой момент в истории типографики, и европейские дизайнеры шрифтов реагируют на эту работу с тех пор. Вероятно, это самый часто возрождаемый шрифт в мире, и многие версии превосходны. Однако в мире свободной/либре‑культуры существует лишь несколько шрифтов, вдохновлённых Гарамондом, и ни один из них не обладает таким масштабом, как этот проект.\nВ ноябре 2019 года семейство было обновлено до вариативного шрифта.', 18, 2, 'https://fonts.google.com/specimen/EB+Garamond', 1, NOW(), NOW()),
('Exo 2', 'Exo 2 — полностью переработанная версия шрифта Exo, современного геометрического шрифта без засечек, который стремится передать технологичное/футуристическое ощущение, сохраняя при этом элегантный дизайн.\n\nExo — очень универсальный шрифт: он включает 9 начертаний (максимальное количество для веба), и каждое из них имеет настоящий курсивный вариант.\n\nУ Exo 2 более органичный вид — благодаря этому шрифт гораздо лучше смотрится в мелком кегле и в длинных текстах.\n\nВ марте 2020 года семейство было обновлено до вариативного шрифта.', 19, 10, 'https://fonts.google.com/specimen/Exo+2', 1, NOW(), NOW()),
('Fira Code', 'Fira Code — это моноширинный шрифт с лигатурами, разработанный для программистов. Основан на Fira Mono, созданном Карлосом Эдуардо Соузой (Carlos Eduardo Soares) для Mozilla. Лицо проекта — Nikita Prokopov. Поддерживает широкий набор лигатур, улучшающих читаемость кода.', 20, 13, 'https://github.com/tonsky/FiraCode', 1, NOW(), NOW()),
('Forum', 'Forum — акцидентный шрифт, вдохновлённый греческими рукописными буквами. Разработан для заголовков и декоративного использования. Имеет выразительные формы и высокую контрастность. Поддерживает латиницу и кириллицу.', 21, 4, 'https://fonts.google.com/specimen/Forum', 1, NOW(), NOW()),
('Gabriela', 'Gabriela — шрифт с засечками, разработанный для литературных и художественных проектов. Обладает тёплым, гуманистическим характером. Поддерживает латинский и кириллический алфавиты.', 22, 2, 'https://fonts.google.com/specimen/Gabriela', 1, NOW(), NOW()),
('Google Sans', 'Google Sans — современный геометрический шрифт без засечек, разработанный для корпоративного брендинга Google. Основан на шрифте Product Sans. Используется в интерфейсах и маркетинговых материалах.', 23, 10, 'https://fonts.google.com/specimen/Google+Sans', 7, NOW(), NOW()),
('Great Vibes', 'Great Vibes — элегантный рукописной шрифт, вдохновлённый каллиграфией XIX века. Подходит для свадебных приглашений, логотипов и заголовков. Поддерживает латиницу.', 8, 11, 'https://fonts.google.com/specimen/Great+Vibes', 1, NOW(), NOW()),
('IBM Plex Sans', 'IBM Plex — семейство шрифтов, разработанное для корпорации IBM. IBM Plex Sans — гуманистический гротеск, сочетающий функциональность и современный дизайн. Поддерживает множество языков, включая кириллицу.', 24, 9, 'https://fonts.google.com/specimen/IBM+Plex+Sans', 1, NOW(), NOW()),
('Inter', 'Inter — геометрический шрифт без засечек, оптимизированный для экранов. Разработан Русланом Хайретдиновым. Широко используется в веб- и мобильных интерфейсах. Поддерживает кириллицу, латиницу и вьетнамский.', 25, 10, 'https://fonts.google.com/specimen/Inter', 1, NOW(), NOW()),
('Jost', 'Jost — геометрический шрифт без засечек, разработанный Йоханом Экерлундом (Johan Aakerlund). Вдохновлён Futura и Avant Garde. Поддерживает латиницу и кириллицу.', 26, 10, 'https://fonts.google.com/specimen/Jost', 1, NOW(), NOW()),
('Kiwi Maru', 'Kiwi Maru — японский шрифт без засечек с мягкими, округлыми формами. Разработан для комфортного чтения на экране. Также включает латинские и кириллические символы.', 27, 8, 'https://fonts.google.com/specimen/Kiwi+Maru', 1, NOW(), NOW()),
('Lato', 'Lato — гуманистический шрифт без засечек, созданный Лукашем Дзякевичем. Изначально разработан для корпоративного использования. Поддерживает широкий набор языков, включая кириллицу.', 28, 9, 'https://fonts.google.com/specimen/Lato', 1, NOW(), NOW()),
('Libre Franklin', 'Libre Franklin — открытая альтернатива Franklin Gothic. Геометрический гротеск, разработанный для универсального использования. Поддерживает латиницу, кириллицу и греческий.', 5, 7, 'https://fonts.google.com/specimen/Libre+Franklin', 1, NOW(), NOW()),
('Lobster', 'Lobster — декоративный рукописной шрифт, вдохновлённый каллиграфией. Подходит для логотипов и заголовков. Поддерживает латиницу и кириллицу.', 5, 11, 'https://fonts.google.com/specimen/Lobster', 1, NOW(), NOW()),
('Lora', 'Lora — шрифт с засечками, разработанный для комфортного чтения на экране. Имеет гуманистический характер. Поддерживает латиницу и кириллицу.', 29, 3, 'https://fonts.google.com/specimen/Lora', 1, NOW(), NOW()),
('LXGW Marker Gothic', 'LXGW Marker Gothic — китайский шрифт в стиле маркера, разработанный для неформального и дружелюбного дизайна. Включает латинские и кириллические символы.', 30, 10, 'https://fonts.google.com/specimen/LXGW+Marker+Gothic', 1, NOW(), NOW()),
('Manrope', 'Manrope — геометрический шрифт без засечек, оптимизированный для веба. Разработан для высокой читаемости. Поддерживает кириллицу и латиницу.', 31, 8, 'https://fonts.google.com/specimen/Manrope', 1, NOW(), NOW()),
('Merriweather', 'Merriweather — шрифт с засечками, разработанный для комфортного чтения на экране. Создан Эриком Шустером. Поддерживает кириллицу, латиницу и греческий.', 32, 2, 'https://fonts.google.com/specimen/Merriweather', 1, NOW(), NOW()),
('Montserrat', 'Montserrat — геометрический шрифт без засечек, вдохновлённый вывесками района Монсеррат в Буэнос-Айресе. Поддерживает кириллицу и латиницу.', 33, 10, 'https://fonts.google.com/specimen/Montserrat', 1, NOW(), NOW()),
('Montserrat Alternates', 'Старые плакаты и вывески в традиционном районе Монтсеррат в Буэнос‑Айресе вдохновили Хулиету (Julieta) на создание этого шрифта и помогли спасти красоту городской типографики, возникшей в первой половине XX века. По мере того как город развивается, район уже никогда не вернётся к своему первоначальному виду и навсегда утратит столь особенные и уникальные дизайны.\n\nБуквы, вдохновившие этот проект, несут в себе труд, преданность делу, заботу, цвет, контраст, свет и жизнь, день и ночь! Именно такие шрифты делают город таким красивым.\n\nПроект Montserrat начался с идеи сохранить то, что есть в Монтсеррате, и выпустить это под свободной лицензией — SIL Open Font License.\n\nЭто семейство Alternates — родственное семейству обычных начертаний и семейству Subrayada. Многие формы букв в семействе Alternates особенные, а слово Subrayada на испанском означает «подчёркнутый» и отдаёт дань особому стилю подчёркивания, интегрированному в формы букв, которые можно встретить в районе Монтсеррат.', 33, 10, 'https://fonts.google.com/specimen/Montserrat+Alternates', 1, NOW(), NOW()),
('Mulish', 'Mulish — геометрический шрифт без засечек с элементами гуманизма. Разработан для цифровых интерфейсов. Поддерживает кириллицу.', 34, 10, 'https://fonts.google.com/specimen/Mulish', 1, NOW(), NOW()),
('Neucha', 'Neucha — рукописной шрифт, разработанный для неформального дизайна. Поддерживает кириллицу и латиницу.', 35, 2, 'https://fonts.google.com/specimen/Neucha', 1, NOW(), NOW()),
('Noto Sans', 'Noto Sans — универсальный шрифт без засечек, разработанный Google для поддержки всех языков мира. Поддерживает кириллицу, латиницу, греческий и многие другие.', 36, 9, 'https://fonts.google.com/noto/specimen/Noto+Sans', 1, NOW(), NOW()),
('Noto Serif', 'Noto Serif — шрифт с засечками из семейства Noto. Разработан для литературных и академических текстов. Поддерживает множество языков.', 36, 3, 'https://fonts.google.com/noto/specimen/Noto+Serif', 1, NOW(), NOW()),
('Nunito', 'Nunito — округлый гуманистический шрифт без засечек. Подходит для дружелюбного дизайна. Поддерживает кириллицу.', 34, 10, 'https://fonts.google.com/specimen/Nunito', 1, NOW(), NOW()),
('Open Sans', 'Open Sans — гуманистический шрифт без засечек, разработанный Стивом Маттесоном. Широко используется в вебе. Поддерживает кириллицу.', 2, 9, 'https://fonts.google.com/specimen/Open+Sans', 1, NOW(), NOW()),
('Oswald', 'Oswald — переработанная версия шрифта Alternate Gothic для цифровых экранов. Геометрический гротеск. Поддерживает кириллицу.', 1, 7, 'https://fonts.google.com/specimen/Oswald', 1, NOW(), NOW()),
('Pacifico', 'Pacifico — рукописной шрифт, вдохновлённый калифорнийским стилем 1970-х. Подходит для логотипов и заголовков. Поддерживает латиницу.', 1, 11, 'https://fonts.google.com/specimen/Pacifico', 1, NOW(), NOW()),
('Philosopher', 'Philosopher — шрифт, разработанный для кириллических и латинских текстов. Поддерживает кириллицу и латиницу.', 35, 9, 'https://fonts.google.com/specimen/Philosopher', 1, NOW(), NOW()),
('Play', 'Play — моноширинный шрифт, разработанный для интерфейсов и игр. Поддерживает кириллицу.', 37, 10, 'https://fonts.google.com/specimen/Play', 1, NOW(), NOW()),
('Playfair Display', 'Playfair Display — шрифт с засечками для заголовков. Вдохновлён типографикой XVIII века. Поддерживает кириллицу.', 38, 3, 'https://fonts.google.com/specimen/Playfair+Display', 1, NOW(), NOW()),
('Podkova', 'Podkova — шрифт с засечками, разработанный для литературных текстов. Поддерживает кириллицу и латиницу.', 29, 5, 'https://fonts.google.com/specimen/Podkova', 1, NOW(), NOW()),
('Press Start 2P', 'Press Start 2P — пиксельный шрифт в стиле ретро-игр. Поддерживает латиницу и кириллицу.', 39, 14, 'https://fonts.google.com/specimen/Press+Start+2P', 1, NOW(), NOW()),
